#include <iostream>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    bool arrive[1000] = {false};

    for (int i = 0; i < m; i++) {
        int num;
        cin >> num;
        arrive[num] = true;
    }

    bool all_arrive = true;
    for (int i = 0; i < n; i++) {
        if (!arrive[i]) {
            cout << i << endl;
            all_arrive = false;
        }
    }

    if (all_arrive) {
        cout << n << endl;
    }

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    int n;
    string s;
    cin >> n >> s;

    int count = 0;
    for (int i = 0; i < n - 1; i++) {
        if (s[i] == 'V' && s[i + 1] == 'K') {
            count++;
            i++;  // 跳过下一个字符
        }
    }

    cout << count << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int l, r;
    cin >> l >> r;

    int count = 0;
    for (int i = l; i <= r; i++) {
        int num = i;
        while (num > 0) {
            if (num % 10 == 2) {
                count++;
            }
            num /= 10;
        }
    }

    cout << count << endl;
    return 0;
}
